// Symbol Database - 15,129+ symbols from all markets
// Merged from portfolio-v4

export interface SymbolEntry {
  n: string;   // name
  e: string;   // exchange
  c: string;   // currency
  s: string;   // sector (Arabic)
  mkt: string; // market
  mc?: number; // market cap (billion)
  div?: number; // dividend yield %
  pe?: number;  // P/E ratio
  eps?: number; // EPS
  t?: string;  // type (e.g., 'sukuk')
  rate?: number; // coupon/yield rate %
}

export type SymbolDB = Record<string, SymbolEntry>;

